// src/lib/data/scan-pages.ts
//
// ScanPage records are per-page summaries within a scan run.
// All counts (totalIssues, resolvedIssues, remainingIssues, criticalRemaining)
// are derived directly from the violation counts in violations.ts.
// Do not edit these numbers without updating violations.ts to match.
//
// Field definitions:
//   totalIssues      = all violations on this page in this scan
//   resolvedIssues   = violations with status "fixed" or "verified"
//   remainingIssues  = violations with status "open" or "in-progress"
//   criticalRemaining = violations with impact "critical" AND status open/in-progress

